"use client"

import { useState, useEffect } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import type React from "react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { signIn } from "next-auth/react"
import { login } from "@/utils/validation"
import { toast } from "sonner"
import { Loader2} from "lucide-react"
import Link from "next/link"
import { Logo } from "@/components/icons"


export function LoginForm({ className, ...props }: React.ComponentPropsWithoutRef<"div">) {
    const router = useRouter()
    const searchParams = useSearchParams()
    const redirectPath = searchParams.get('redirect')
    const [emailValue, setEmailValue] = useState("")
    const [passwordValue, setPasswordValue] = useState("")
    const [isLoading, setIsLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({})



    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault()
        setError(null)
        setFieldErrors({})

        // Prevent double submission
        if (isLoading) {
            return
        }

        // Validate using zod schema
        const result = login.safeParse({
            type: 'email',
            email: emailValue.trim(),
            password: passwordValue,
        })


        if (!result.success) {
            const errors: Record<string, string> = {}
            result.error.issues.forEach((err) => {
                if (err.path.length > 0) {
                    const field = err.path[0] as string
                    errors[field] = err.message
                }
            })
            setFieldErrors(errors)

            // Show first error as general error
            if (result.error.issues.length > 0) {
                setError(result.error.issues[0].message)
            }
            return
        }

        setIsLoading(true)

        try {
            // Add timeout to detect connection issues
            const timeoutPromise = new Promise((_, reject) => {
                setTimeout(() => reject(new Error('Timeout: Không thể kết nối đến server. Vui lòng kiểm tra lại kết nối.')), 10000)
            })

            const signInPromise = signIn("credentials", {
                email: emailValue.trim(),
                password: passwordValue,
                redirect: false,
            })

            const result = await Promise.race([signInPromise, timeoutPromise]) as any

            if (result?.error) {
                // NextAuth doesn't pass custom error messages, so we check for common error types
                // If authorize throws, NextAuth returns generic error
                // We'll show connection error if we detect it was a network issue
                setError('Đăng nhập thất bại. Vui lòng kiểm tra lại email và mật khẩu.')
                toast.error('Đăng nhập thất bại. Vui lòng kiểm tra lại email và mật khẩu.')
            } else if (result?.ok) {
                // Show success message
                toast.success('Đăng nhập thành công!', {
                    description: 'Đang chuyển hướng...',
                    duration: 2000,
                })

                // Small delay to show success message before redirect
                await new Promise(resolve => setTimeout(resolve, 800))

                // Redirect to the original path if exists, otherwise go to home
                const redirectTo = redirectPath || '/dashboard'
                router.push(redirectTo)
                router.refresh()
            } else {
                // If result is null or undefined, it might be a connection issue
                setError('Không thể kết nối đến server. Vui lòng kiểm tra lại kết nối hoặc đảm bảo server đã được khởi động.')
                toast.error('Không thể kết nối đến server. Vui lòng kiểm tra lại kết nối.')
            }
        } catch (err: any) {
            if (err?.message?.includes('Timeout') || err?.message?.includes('CONNECTION_ERROR')) {
                const errorMsg = 'Không thể kết nối đến server. Vui lòng đảm bảo server backend đã được khởi động.'
                setError(errorMsg)
                toast.error(errorMsg)
            } else {
                const errorMessage = err?.message || 'Đăng nhập thất bại. Vui lòng thử lại.'
                setError(errorMessage)
                toast.error(errorMessage)
            }
        } finally {
            setIsLoading(false)
        }
    }

    useEffect(() => {
        if (redirectPath) {
            toast.warning(`Bạn cần đăng nhập để truy cập trang`)
        }
    }, [redirectPath])

    return (
        <div className={cn("flex flex-col gap-6", className)} {...props}>
            {/* Logo với link về trang chủ */}
            <Link
                href="/dashboard"
                aria-label="Về trang chủ"
                className="flex lg:hidden  gap-2 rounded-md hover:opacity-80 transition-opacity focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            >
                <div className="bg-red-500 p-1.5 rounded-lg shadow-lg shadow-red-500/30">
                    <Logo className="w-6 h-6 text-white" />
                </div>
                <h2 className="text-xl md:text-2xl font-bold tracking-tight">
                    <span className="text-red-600">Guard</span>M
                </h2>
            </Link>

            <Card className="border-dashed border-gray-300">
                <CardHeader className="text-center">
                    <CardTitle className="text-xl">Welcome</CardTitle>
                    <CardDescription>Đăng nhập vào hệ thống để xem thông tin tội phạm và các cảnh báo gần bạn</CardDescription>
                </CardHeader>
                <CardContent>
                    <form onSubmit={handleSubmit}>
                        <div className="grid gap-6">
                            {/* <div className="flex flex-col gap-4">
                                <Button variant="outline" className="w-full" type="button">
                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
                                        <path
                                            d="M12.48 10.92v3.28h7.84c-.24 1.84-.853 3.187-1.787 4.133-1.147 1.147-2.933 2.4-6.053 2.4-4.827 0-8.6-3.893-8.6-8.72s3.773-8.72 8.6-8.72c2.6 0 4.507 1.027 5.907 2.347l2.307-2.307C18.747 1.44 16.133 0 12.48 0 5.867 0 .307 5.387.307 12s5.56 12 12.173 12c3.573 0 6.267-1.173 8.373-3.36 2.16-2.16 2.84-5.213 2.84-7.667 0-.76-.053-1.467-.173-2.053H12.48z"
                                            fill="currentColor"
                                        />
                                    </svg>
                                    Login with Google
                                </Button>
                            </div>
                            <div className="relative text-center text-sm after:absolute after:inset-0 after:top-1/2 after:z-0 after:flex after:items-center after:border-t after:border-border">
                                <span className="relative z-10 bg-background px-2 text-muted-foreground">Or continue with</span>
                            </div> */}
                            <div className="grid gap-6">
                                {error && (
                                    <div className="rounded-md bg-red-50 dark:bg-red-950/50 border border-red-200 dark:border-red-800 p-3 text-sm text-red-600 dark:text-red-400">
                                        {error}
                                    </div>
                                )}
                                <div className="grid gap-2">
                                    <Label htmlFor="email">Email</Label>
                                    <Input
                                        id="email"
                                        type="email"
                                        placeholder="m@example.com"
                                        required
                                        value={emailValue}
                                        onChange={(e) => {
                                            setEmailValue(e.target.value)
                                            if (fieldErrors.email) {
                                                setFieldErrors({ ...fieldErrors, email: '' })
                                            }
                                        }}
                                        disabled={isLoading}
                                        className={fieldErrors.email ? "border-red-500" : ""}
                                    />
                                    {fieldErrors.email && (
                                        <p className="text-sm text-red-600">{fieldErrors.email}</p>
                                    )}
                                </div>
                                <div className="grid gap-2">
                                    <div className="flex items-center">
                                        <Label htmlFor="password">Password</Label>
                                        {/* <a href="#" className="ml-auto text-sm underline-offset-4 hover:underline">
                                            Forgot your password?
                                        </a> */}
                                    </div>
                                    <Input
                                        id="password"
                                        type="password"
                                        placeholder="password"
                                        required
                                        value={passwordValue}
                                        onChange={(e) => {
                                            setPasswordValue(e.target.value)
                                            if (fieldErrors.password) {
                                                setFieldErrors({ ...fieldErrors, password: '' })
                                            }
                                        }}
                                        disabled={isLoading}
                                        className={fieldErrors.password ? "border-red-500" : ""}
                                    />
                                    {fieldErrors.password && (
                                        <p className="text-sm text-red-600">{fieldErrors.password}</p>
                                    )}
                                </div>
                                <Button type="submit" className="w-full bg-red-600" disabled={isLoading}>
                                    {isLoading ? (
                                        <>
                                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                            Đang đăng nhập...
                                        </>
                                    ) : (
                                        "Login"
                                    )}
                                </Button>
                            </div>
                            <div className="text-center text-sm">
                                Chưa có tài khoản?{" "}
                                <a href="/signup" className="underline underline-offset-4">
                                    Đăng ký
                                </a>
                            </div>
                        </div>
                    </form>
                </CardContent>
            </Card>
            <div className="text-balance text-center text-xs text-muted-foreground [&_a]:underline [&_a]:underline-offset-4 [&_a]:hover:text-primary  ">
                By clicking continue, you agree to our <a href="#">Terms of Service</a> and <a href="#">Privacy Policy</a>.
            </div>
        </div>
    )
}

"use client"

import { useState } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import type React from "react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import authService from "@/service/auth.service"
import { signUp } from "@/utils/validation"
import { toast } from "sonner"
import { signIn } from "next-auth/react"
import { Loader2 } from "lucide-react"
import Link from "next/link"
import { Logo } from "@/components/icons"

export function SignupForm({ className, ...props }: React.ComponentPropsWithoutRef<"div">) {
    const router = useRouter()
    const searchParams = useSearchParams()
    const redirectPath = searchParams.get('redirect')
    const [name, setName] = useState("")
    const [email, setEmail] = useState("")
    const [password, setPassword] = useState("")
    const [confirmPassword, setConfirmPassword] = useState("")
    const [isLoading, setIsLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({})

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault()
        setError(null)
        setFieldErrors({})

        // Prevent double submission
        if (isLoading) {
            return
        }

        // Validate using zod schema
        const result = signUp.safeParse({
            name: name.trim(),
            email: email.trim(),
            password,
            confirmPassword,
        })

        if (!result.success) {
            const errors: Record<string, string> = {}
            result.error.issues.forEach((err) => {
                if (err.path.length > 0) {
                    const field = err.path[0] as string
                    errors[field] = err.message
                }
            })
            setFieldErrors(errors)

            // Show first error as general error
            if (result.error.issues.length > 0) {
                setError(result.error.issues[0].message)
            }
            return
        }

        setIsLoading(true)

        try {
            await authService.signup({
                name: name.trim(),
                email: email.trim().toLowerCase(),
                password,
            })

            // Tự động đăng nhập sau khi đăng ký thành công
            const loginResult = await signIn("credentials", {
                email: email.trim().toLowerCase(),
                password: password,
                redirect: false,
            })

            if (loginResult?.error) {
                // Nếu đăng nhập thất bại, redirect đến login page
                toast.error('Đăng ký thành công nhưng đăng nhập thất bại. Vui lòng đăng nhập thủ công.')
                router.push('/login')
                router.refresh()
            } else if (loginResult?.ok) {
                // Đăng nhập thành công, redirect đến trang ban đầu hoặc trang chủ
                toast.success('Đăng ký thành công!', {
                    description: 'Đang chuyển hướng...',
                    duration: 2000,
                })

                // Small delay to show success message before redirect
                await new Promise(resolve => setTimeout(resolve, 800))

                const redirectTo = redirectPath || "/dashboard"
                router.push(redirectTo)
                router.refresh()
            }
        } catch (err: any) {
            console.error('[Signup] Error:', err)
            console.error('[Signup] Error response:', err?.response?.data)
            console.error('[Signup] Error message:', err?.message)

            // Error đã được format trong authService
            const errorMessage = err?.message ||
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                err?.response?.data ||
                'Đăng ký thất bại. Vui lòng thử lại.'

            setError(typeof errorMessage === 'string' ? errorMessage : JSON.stringify(errorMessage))
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <div className={cn("flex flex-col gap-6", className)} {...props}>
            {/* Logo với link về trang chủ */}
            <Link
                href="/dashboard"
                aria-label="Về trang chủ"
                className="flex sm:hidden  gap-2 rounded-md hover:opacity-80 transition-opacity focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            >
                <div className="bg-red-500 p-1.5 rounded-lg shadow-lg shadow-red-500/30">
                    <Logo className="w-6 h-6 text-white" />
                </div>
                <h2 className="text-xl md:text-2xl font-bold tracking-tight">
                    <span className="text-red-600">GuardM</span>
                </h2>
            </Link>

            <Card className="border-dashed border-gray-300">
                <CardHeader className="text-center">
                    <CardTitle className="text-xl">Đăng ký</CardTitle>
                    <CardDescription>Tạo tài khoản mới để sử dụng hệ thống</CardDescription>
                </CardHeader>
                <CardContent>
                    <form onSubmit={handleSubmit}>
                        <div className="grid gap-6">
                            <div className="grid gap-6">
                                {error && (
                                    <div className="rounded-md bg-red-50 p-3 text-sm text-red-600">
                                        {error}
                                    </div>
                                )}
                                <div className="grid gap-2">
                                    <Label htmlFor="name">Họ và tên</Label>
                                    <Input
                                        id="name"
                                        type="text"
                                        placeholder="Nguyễn Văn A"
                                        required
                                        value={name}
                                        onChange={(e) => {
                                            setName(e.target.value)
                                            if (fieldErrors.name) {
                                                setFieldErrors({ ...fieldErrors, name: '' })
                                            }
                                        }}
                                        disabled={isLoading}
                                        className={fieldErrors.name ? "border-red-500" : ""}
                                    />
                                    {fieldErrors.name && (
                                        <p className="text-sm text-red-600">{fieldErrors.name}</p>
                                    )}
                                </div>
                                <div className="grid gap-2">
                                    <Label htmlFor="email">Email</Label>
                                    <Input
                                        id="email"
                                        type="email"
                                        placeholder="m@example.com"
                                        required
                                        value={email}
                                        onChange={(e) => {
                                            setEmail(e.target.value)
                                            if (fieldErrors.email) {
                                                setFieldErrors({ ...fieldErrors, email: '' })
                                            }
                                        }}
                                        disabled={isLoading}
                                        className={fieldErrors.email ? "border-red-500" : ""}
                                    />
                                    {fieldErrors.email && (
                                        <p className="text-sm text-red-600">{fieldErrors.email}</p>
                                    )}
                                </div>
                                <div className="grid gap-2">
                                    <Label htmlFor="password">Mật khẩu</Label>
                                    <Input
                                        id="password"
                                        type="password"
                                        placeholder="mật khẩu"
                                        required
                                        value={password}
                                        onChange={(e) => {
                                            setPassword(e.target.value)
                                            if (fieldErrors.password) {
                                                setFieldErrors({ ...fieldErrors, password: '' })
                                            }
                                        }}
                                        disabled={isLoading}
                                        className={fieldErrors.password ? "border-red-500" : ""}
                                    />
                                    {fieldErrors.password && (
                                        <p className="text-sm text-red-600">{fieldErrors.password}</p>
                                    )}
                                </div>
                                <div className="grid gap-2">
                                    <Label htmlFor="confirmPassword">Xác nhận mật khẩu</Label>
                                    <Input
                                        id="confirmPassword"
                                        type="password"
                                        placeholder="Nhập lại mật khẩu"
                                        required
                                        value={confirmPassword}
                                        onChange={(e) => {
                                            setConfirmPassword(e.target.value)
                                            if (fieldErrors.confirmPassword) {
                                                setFieldErrors({ ...fieldErrors, confirmPassword: '' })
                                            }
                                        }}
                                        disabled={isLoading}
                                        className={fieldErrors.confirmPassword ? "border-red-500" : ""}
                                    />
                                    {fieldErrors.confirmPassword && (
                                        <p className="text-sm text-red-600">{fieldErrors.confirmPassword}</p>
                                    )}
                                </div>
                                <Button type="submit" className="w-full" disabled={isLoading}>
                                    {isLoading ? (
                                        <>
                                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                            Đang đăng ký...
                                        </>
                                    ) : (
                                        "Đăng ký"
                                    )}
                                </Button>
                            </div>
                            <div className="text-center text-sm">
                                Đã có tài khoản?{" "}
                                <a href="/login" className="underline underline-offset-4">
                                    Đăng nhập
                                </a>
                            </div>
                        </div>
                    </form>
                </CardContent>
            </Card>
            <div className="text-balance text-center text-xs text-muted-foreground [&_a]:underline [&_a]:underline-offset-4 [&_a]:hover:text-primary">
                By clicking continue, you agree to our <a href="/terms">Terms of Service</a> and <a href="/privacy">Privacy Policy</a>.
            </div>
        </div>
    )
}

'use client';

import React, { useEffect, useRef, useState } from 'react';
import { ChevronRight } from 'lucide-react';

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';

const GLOBE_SIZE = 450;
const GLOBE_RADIUS = GLOBE_SIZE / 2;
const MAP_CIRCUMFERENCE = 2 * Math.PI * GLOBE_RADIUS;

interface HeroProps {
    appUrl: string;
}

const CustomTechEarth = () => {
    const [rotation, setRotation] = useState(0);
    const requestRef = useRef<number | null>(null);

    const animate = () => {
        setRotation((prev) => prev + 0.002);
        requestRef.current = requestAnimationFrame(animate);
    };

    useEffect(() => {
        requestRef.current = requestAnimationFrame(animate);
        return () => {
            if (requestRef.current) {
                cancelAnimationFrame(requestRef.current);
            }
        };
    }, []);

    const rotationRatio = (rotation % (2 * Math.PI)) / (2 * Math.PI);
    const bgPosition = rotationRatio * MAP_CIRCUMFERENCE;

    return (
        <div
            className="relative flex items-center justify-center aspect-square w-full max-w-[450px] md:max-w-[500px] transform scale-90 md:scale-100 transition-transform duration-500"
        >
            <div className="absolute inset-0 rounded-full bg-[#0EA5E9] overflow-hidden border border-slate-200/60">
                <div
                    className="absolute top-0 left-0 h-full opacity-55"
                    style={{
                        width: '100%',
                        height: '100%',
                        backgroundImage:
                            "url('/world-map.png')",
                        backgroundSize: `${MAP_CIRCUMFERENCE}px 100%`,
                        backgroundRepeat: 'repeat-x',
                        backgroundPosition: `${-bgPosition}px center`,
                        filter: 'saturate(1.2)',
                    }}
                ></div>

                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-size-[45px_45px] rounded-full opacity-20"></div>
                <div className="absolute inset-0 rounded-full bg-[radial-gradient(circle_at_30%_30%,rgba(255,255,255,0.05),transparent_60%,rgba(0,0,0,0.8)_100%)] pointer-events-none"></div>
            </div>

            <div className="absolute inset-[-2px] rounded-full border border-blue-500/30 blur-[1px]"></div>
            <div className="absolute inset-[-30px] rounded-full bg-blue-500/10 blur-2xl -z-10"></div>
        </div>
    );
};

export const HeroSection: React.FC<HeroProps> = ({ appUrl }) => {
    return (
        <section className="relative pt-15 pb-10 px-6 lg:h-screen min-h-[800px] flex items-center overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full bg-linear-to-br from-white via-blue-50 to-indigo-100 -z-20"></div>
            <div className="absolute top-1/2 right-0 w-[500px] h-[500px] bg-blue-200/40 rounded-full blur-[160px] -z-10 pointer-events-none"></div>

            <div className="max-w-7xl mx-auto w-full sm:px-6 py-10 flex flex-col sm:grid lg:grid-cols-2 gap-10 items-center h-full">
                <div className="space-y-2 z-10">
                    <Badge
                        variant="outline"
                        className="bg-red-100 text-red-600 border-red-200 font-semibold uppercase tracking-wider px-3 "
                    >
                        Global Monitoring
                    </Badge>

                    <h1 className="text-3xl sm:text-5xl md:text-6xl lg:text-7xl font-bold text-slate-900 leading-[1.1] tracking-tight">
                        Bản đồ cảnh báo tội phạm
                    </h1>

                    <p className="text-slate-600 text-base sm:text-lg  max-w-lg leading-relaxed">
                        GuardM không chỉ là landing page demo, mà là bộ ứng dụng hoàn chỉnh gồm
                        dashboard thống kê, bản đồ tội phạm, báo cáo người dân, danh sách truy nã
                        và cảnh báo thời tiết được kết nối với dữ liệu thật.
                    </p>

                    <div className="flex flex-col sm:flex-row gap-4 pt-4">
                        <Button
                            asChild
                            size="lg"
                            className="text-base font-semibold shadow-[0_0_25px_rgba(220,38,38,0.4)]"
                        >
                            <a href={appUrl} className="flex items-center gap-2">
                                Truy cập ứng dụng
                                <ChevronRight className="w-5 h-5" />
                            </a>
                        </Button>

                    </div>
                </div>

                <div id="demo" className="relative hidden sm:block h-[400px] lg:h-[600px] w-full flex items-center justify-center perspective-1000">
                    <CustomTechEarth />
                </div>
            </div>
        </section>
    );
}

'use client';

import { useState } from 'react';
import { toast } from 'sonner';
import { CheckCircle2, Loader2, AlertCircle } from 'lucide-react';
