const verificationLevelLabels: Record<VerificationLevel, string> = {
    [VerificationLevel.UNVERIFIED]: 'Chưa xác minh',
    [VerificationLevel.PENDING]: 'Đang chờ',
    [VerificationLevel.CONFIRMED]: 'Đã xác minh',
    [VerificationLevel.VERIFIED]: 'Đã xác thực',
};

const verificationLevelColors: Record<VerificationLevel, string> = {
    [VerificationLevel.UNVERIFIED]: 'bg-gray-500',
    [VerificationLevel.PENDING]: 'bg-yellow-500',
    [VerificationLevel.CONFIRMED]: 'bg-green-500',
    [VerificationLevel.VERIFIED]: 'bg-blue-500',
};

export default function AdminReportsPage() {
    const { data: reports = [], isLoading, error } = useReportsQuery();
    const verifyReportMutation = useAdminVerifyReport();

    const [verifyDialogOpen, setVerifyDialogOpen] = useState(false);
    const [selectedReport, setSelectedReport] = useState<VerificationCrimeReport | null>(null);

    // Filter unverified reports
    const unverifiedReports = reports.filter(
        (r) => r.verificationLevel === VerificationLevel.UNVERIFIED || r.verificationLevel === VerificationLevel.PENDING
    );

    const handleVerify = async () => {
        if (!selectedReport) return;

        try {
            await verifyReportMutation.mutateAsync(selectedReport.id);
            toast.success('Đã xác minh báo cáo thành công');
            setVerifyDialogOpen(false);
            setSelectedReport(null);
        } catch (err: any) {
            toast.error(err?.message || 'Không thể xác minh báo cáo');
        }
    };

    const openVerifyDialog = (report: VerificationCrimeReport) => {
        setSelectedReport(report);
        setVerifyDialogOpen(true);
    };

    if (error) {
        return (
            <div className="p-6">
                <Card>
                    <CardContent className="pt-6">
                        <div className="flex items-center gap-2 text-destructive">
                            <AlertCircle className="w-5 h-5" />
                            <p>Có lỗi xảy ra: {error.message}</p>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            <div>
                <h1 className="text-3xl font-bold">Xác minh báo cáo</h1>
                <p className="text-muted-foreground">
                    Xác minh các báo cáo tội phạm từ người dùng
                </p>
            </div>

            <div className="grid gap-4 md:grid-cols-3">
                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-sm font-medium">Tổng báo cáo</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{reports.length}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-sm font-medium">Chờ xác minh</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-yellow-600">
                            {unverifiedReports.length}
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-sm font-medium">Đã xác minh</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-600">
                            {reports.filter((r) => r.verificationLevel === VerificationLevel.VERIFIED || r.verificationLevel === VerificationLevel.CONFIRMED).length}
                        </div>
                    </CardContent>
                </Card>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Báo cáo chờ xác minh</CardTitle>
                    <CardDescription>
                        {unverifiedReports.length} báo cáo cần xác minh
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    {isLoading ? (
                        <div className="flex items-center justify-center py-8">
                            <Loader2 className="w-6 h-6 animate-spin" />
                        </div>
                    ) : unverifiedReports.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground">
                            Không có báo cáo nào cần xác minh
                        </div>
                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Tiêu đề</TableHead>
                                    <TableHead>Loại</TableHead>
                                    <TableHead>Địa chỉ</TableHead>
                                    <TableHead>Trust Score</TableHead>
                                    <TableHead>Trạng thái</TableHead>
                                    <TableHead className="text-right">Hành động</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {unverifiedReports.map((report) => (
                                    <TableRow key={report.id}>
                                        <TableCell className="font-medium">
                                            {report.title || 'Không có tiêu đề'}
                                        </TableCell>
                                        <TableCell>{report.type}</TableCell>
                                        <TableCell className="max-w-xs truncate">
                                            {report.address || 'Không có địa chỉ'}
                                        </TableCell>
                                        <TableCell>
                                            <Badge variant={report.trustScore >= 50 ? 'default' : 'secondary'}>
                                                {report.trustScore}
                                            </Badge>
                                        </TableCell>
                                        <TableCell>
                                            <Badge
                                                className={
                                                    verificationLevelColors[report.verificationLevel] ||
                                                    'bg-gray-500'
                                                }
                                            >
                                                {verificationLevelLabels[report.verificationLevel] ||
                                                    report.verificationLevel}
                                            </Badge>
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <Button
                                                size="sm"
                                                onClick={() => openVerifyDialog(report)}
                                            >
                                                <CheckCircle2 className="w-4 h-4 mr-1" />
                                                Xác minh
                                            </Button>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>

            {/* Verify Confirmation Dialog */}
            <AlertDialog open={verifyDialogOpen} onOpenChange={setVerifyDialogOpen}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Xác nhận xác minh</AlertDialogTitle>
                        <AlertDialogDescription>
                            Bạn có chắc chắn muốn xác minh báo cáo{' '}
                            <strong>{selectedReport?.title}</strong>?
                            <br />
                            <br />
                            Báo cáo sẽ được đánh dấu là <strong>Đã xác thực</strong> với Trust Score = 100.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Hủy</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleVerify}
                            disabled={verifyReportMutation.isPending}
                        >
                            {verifyReportMutation.isPending && (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            )}
                            Xác minh
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { toast } from 'sonner';
import { Database, CloudRain, RefreshCw } from 'lucide-react';
import {
    useScraperStatusQuery,
    useTriggerWantedCriminalsScraper,
    useTriggerWeatherNewsScraper,
} from '@/hooks/use-scraper';
import { ScraperCard } from '../components/ScraperCard';
import { Card, CardContent,  CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';

export default function AdminScraperPage() {
    const { data: scraperStatus, isLoading, refetch } = useScraperStatusQuery();
    const triggerWantedCriminalsMutation = useTriggerWantedCriminalsScraper();
    const triggerWeatherNewsMutation = useTriggerWeatherNewsScraper();

    const [wantedCriminalsPages, setWantedCriminalsPages] = useState(5);
    const [wantedCriminalsLimit, setWantedCriminalsLimit] = useState<number | undefined>(undefined);

    const handleTriggerWantedCriminals = async () => {
        try {
            const result = await triggerWantedCriminalsMutation.mutateAsync({ 
                pages: wantedCriminalsPages,
                limit: wantedCriminalsLimit
            });
            toast.success(result.message || `Đã scrape ${result.count} đối tượng truy nã`);
        } catch (err: any) {
            toast.error(err?.message || 'Không thể kích hoạt scraper');
        }
    };

    const handleTriggerWeatherNews = async () => {
        try {
            const result = await triggerWeatherNewsMutation.mutateAsync();
            toast.success(
                result.message ||
                    `Đã scrape ${result.count} tin thời tiết (${result.imported} mới, ${result.updated} cập nhật)`
            );
        } catch (err: any) {
            toast.error(err?.message || 'Không thể kích hoạt scraper');
        }
    };

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold">Quản lý Scraper</h1>
                    <p className="text-muted-foreground">
                        Kích hoạt và theo dõi các scraper tự động
                    </p>
                </div>
                <Button variant="outline" onClick={() => refetch()} disabled={isLoading}>
                    <RefreshCw className={`w-4 h-4 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
                    Làm mới
                </Button>
            </div>

            <div className="grid gap-6 md:grid-cols-2">
                {/* Wanted Criminals Scraper */}
                <div className="space-y-4">
                    <ScraperCard
                        title="Đối tượng truy nã"
                        description="Scrape danh sách truy nã từ Bộ Công An"
                        status={scraperStatus?.wantedCriminals}
                        onTrigger={handleTriggerWantedCriminals}
                        isTriggering={triggerWantedCriminalsMutation.isPending}
                        icon={<Database className="w-6 h-6" />}
                    />
                    <Card>
                        <CardHeader>
                            <CardTitle className="text-sm">Cấu hình</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <Label htmlFor="pages">Số trang scrape (Mặc định: 5)</Label>
                                    <Input
                                        id="pages"
                                        type="number"
                                        min={1}
                                        max={50}
                                        value={wantedCriminalsPages}
                                        onChange={(e) => setWantedCriminalsPages(Number(e.target.value))}
                                        disabled={!!wantedCriminalsLimit}
                                    />
                                    <p className="text-xs text-muted-foreground">
                                        Mỗi trang chứa khoảng 30 đối tượng
                                    </p>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="limit">Giới hạn số lượng (Tùy chọn)</Label>
                                    <Input
                                        id="limit"
                                        type="number"
                                        min={1}
                                        placeholder="Nhập số lượng giới hạn (VD: 100)"
                                        value={wantedCriminalsLimit || ''}
                                        onChange={(e) => {
                                            const val = e.target.value ? Number(e.target.value) : undefined;
                                            setWantedCriminalsLimit(val);
                                        }}
                                    />
                                    <p className="text-xs text-muted-foreground">
                                        Nếu nhập giới hạn, số trang sẽ bị bỏ qua
                                    </p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Weather News Scraper */}
                <ScraperCard
                    title="Tin thời tiết & thiên tai"
                    description="Scrape tin tức thời tiết từ NCHMF"
                    status={scraperStatus?.weatherNews}
                    onTrigger={handleTriggerWeatherNews}
                    isTriggering={triggerWeatherNewsMutation.isPending}
                    icon={<CloudRain className="w-6 h-6" />}
                />
            </div>

            {/* Info Card */}
            <Card>
                <CardHeader>
                    <CardTitle>Lưu ý</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2 text-sm text-muted-foreground">
                    <p>• Scraper sẽ tự động cập nhật dữ liệu mới và xóa dữ liệu cũ</p>
                    <p>• Thời gian chạy có thể từ vài giây đến vài phút tùy thuộc vào số lượng dữ liệu</p>
                    <p>• Nên chạy scraper vào giờ thấp điểm để tránh ảnh hưởng đến người dùng</p>
                    <p>• Kiểm tra log server để xem chi tiết quá trình scraping</p>
                </CardContent>
            </Card>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { toast } from 'sonner';
import { useRouter } from 'next/navigation';
import { Plus, Pencil, Trash2, Loader2, ArrowLeft } from 'lucide-react';
import { useUsersQuery, useCreateUser, useUpdateUser, useDeleteUser } from '@/hooks/use-users';
import { User, CreateUserDto, UpdateUserDto, Role } from '@/service/user.service';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';

const roleColors: Record<Role, string> = {
    [Role.Admin]: 'bg-red-500',
    [Role.Officer]: 'bg-blue-500',
    [Role.User]: 'bg-gray-500',
};

export default function AdminUsersPage() {
    const router = useRouter();
    const { data: users = [], isLoading, error } = useUsersQuery();
    const createUserMutation = useCreateUser();
    const updateUserMutation = useUpdateUser();
    const deleteUserMutation = useDeleteUser();

    const [createDialogOpen, setCreateDialogOpen] = useState(false);
    const [editDialogOpen, setEditDialogOpen] = useState(false);
    const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);

    // Form states
    const [formData, setFormData] = useState<CreateUserDto>({
        name: '',
        email: '',
        password: '',
        role: Role.User,
    });

    const resetForm = () => {
        setFormData({
            name: '',
            email: '',
            password: '',
            role: Role.User,
        });
    };

    const handleCreate = async () => {
        try {
            await createUserMutation.mutateAsync(formData);
            toast.success('Tạo người dùng thành công');
            setCreateDialogOpen(false);
            resetForm();
        } catch (err: any) {
            toast.error(err?.message || 'Không thể tạo người dùng');
        }
    };

    const handleEdit = async () => {
        if (!selectedUser) return;

        const updateData: UpdateUserDto = {
            name: formData.name,
            email: formData.email,
            role: formData.role,
        };

        try {
            await updateUserMutation.mutateAsync({ id: selectedUser.id, payload: updateData });
            toast.success('Cập nhật người dùng thành công');
            setEditDialogOpen(false);
            setSelectedUser(null);
            resetForm();
        } catch (err: any) {
            toast.error(err?.message || 'Không thể cập nhật người dùng');
        }
    };

    const handleDelete = async () => {
        if (!selectedUser) return;

        try {
            await deleteUserMutation.mutateAsync(selectedUser.id);
            toast.success('Xóa người dùng thành công');
            setDeleteDialogOpen(false);
            setSelectedUser(null);
        } catch (err: any) {
            toast.error(err?.message || 'Không thể xóa người dùng');
        }
    };

    const openEditDialog = (user: User) => {
        setSelectedUser(user);
        setFormData({
            name: user.name,
            email: user.email,
            password: '', // Don't show password
            role: user.role,
        });
        setEditDialogOpen(true);
    };

    const openDeleteDialog = (user: User) => {
        setSelectedUser(user);
        setDeleteDialogOpen(true);
    };

    if (error) {
        return (
            <div className="p-6">
                <Card>
                    <CardContent className="pt-6">
                        <p className="text-destructive">Có lỗi xảy ra: {error.message}</p>
                    </CardContent>
                </Card>
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <Button variant="ghost" size="icon" onClick={() => router.back()}>
                        <ArrowLeft className="w-4 h-4" />
                    </Button>
                    <div>
                        <h1 className="text-3xl font-bold">Quản lý người dùng</h1>
                        <p className="text-muted-foreground">Quản lý tài khoản người dùng trong hệ thống</p>
                    </div>
                </div>
                <Button onClick={() => setCreateDialogOpen(true)}>
                    <Plus className="w-4 h-4 mr-2" />
                    Thêm người dùng
                </Button>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Danh sách người dùng</CardTitle>
                    <CardDescription>Tổng số: {users.length} người dùng</CardDescription>
                </CardHeader>
                <CardContent>
                    {isLoading ? (
                        <div className="flex items-center justify-center py-8">
                            <Loader2 className="w-6 h-6 animate-spin" />
                        </div>
                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Tên</TableHead>
                                    <TableHead>Email</TableHead>
                                    <TableHead>Vai trò</TableHead>
                                    <TableHead className="text-right">Hành động</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {users.map((user) => (
                                    <TableRow key={user.id}>
                                        <TableCell className="font-medium">{user.name}</TableCell>
                                        <TableCell>{user.email}</TableCell>
                                        <TableCell>
                                            <Badge className={roleColors[user.role]}>
                                                {user.role}
                                            </Badge>
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <div className="flex justify-end gap-2">
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={() => openEditDialog(user)}
                                                >
                                                    <Pencil className="w-4 h-4" />
                                                </Button>
                                                <Button
                                                    variant="destructive"
                                                    size="sm"
                                                    onClick={() => openDeleteDialog(user)}
                                                >
                                                    <Trash2 className="w-4 h-4" />
                                                </Button>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>

            {/* Create Dialog */}
            <Dialog open={createDialogOpen} onOpenChange={setCreateDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Thêm người dùng mới</DialogTitle>
                        <DialogDescription>
                            Tạo tài khoản người dùng mới trong hệ thống
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="create-name">Tên</Label>
                            <Input
                                id="create-name"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                placeholder="Nhập tên người dùng"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="create-email">Email</Label>
                            <Input
                                id="create-email"
                                type="email"
                                value={formData.email}
                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                placeholder="email@example.com"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="create-password">Mật khẩu</Label>
                            <Input
                                id="create-password"
                                type="password"
                                value={formData.password}
                                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                placeholder="Tối thiểu 6 ký tự, có ít nhất 1 số"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="create-role">Vai trò</Label>
                            <Select
                                value={formData.role}
                                onValueChange={(value) => setFormData({ ...formData, role: value as Role })}
                            >
                                <SelectTrigger id="create-role">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value={Role.User}>User</SelectItem>
                                    <SelectItem value={Role.Officer}>Officer</SelectItem>
                                    <SelectItem value={Role.Admin}>Admin</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setCreateDialogOpen(false)}>
                            Hủy
                        </Button>
                        <Button onClick={handleCreate} disabled={createUserMutation.isPending}>
                            {createUserMutation.isPending && (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            )}
                            Tạo
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Edit Dialog */}
            <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Chỉnh sửa người dùng</DialogTitle>
                        <DialogDescription>
                            Cập nhật thông tin người dùng
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="edit-name">Tên</Label>
                            <Input
                                id="edit-name"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="edit-email">Email</Label>
                            <Input
                                id="edit-email"
                                type="email"
                                value={formData.email}
                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="edit-role">Vai trò</Label>
                            <Select
                                value={formData.role}
                                onValueChange={(value) => setFormData({ ...formData, role: value as Role })}
                            >
                                <SelectTrigger id="edit-role">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value={Role.User}>User</SelectItem>
                                    <SelectItem value={Role.Officer}>Officer</SelectItem>
                                    <SelectItem value={Role.Admin}>Admin</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setEditDialogOpen(false)}>
                            Hủy
                        </Button>
                        <Button onClick={handleEdit} disabled={updateUserMutation.isPending}>
                            {updateUserMutation.isPending && (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            )}
                            Cập nhật
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Delete Confirmation Dialog */}
            <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Xác nhận xóa</AlertDialogTitle>
                        <AlertDialogDescription>
