'use client';

import { useEffect } from 'react';
import { VerificationLevel } from '@/types/map';
import { VerificationCrimeReport } from '@/types/map';

interface UseMapCrimeMarkersProps {
    isLeafletLoaded: boolean;
    mapInstanceRef: React.MutableRefObject<any>;
    markersLayerRef: React.MutableRefObject<any>;
    reports: VerificationCrimeReport[];
    onMarkerClick: (reportId: string) => void;
    selectedReportId?: string | null;
}

// Màu marker dựa trên mức độ nghiêm trọng (severityLevel)
const severityColorMap: Record<string, { hex: string; rgb: string; shadow: string }> = {
    low: { hex: '#56a381', rgb: '86, 163, 129', shadow: '0 0 0 2px rgba(86, 163, 129, 0.3)' },      // Xanh - Nguy hiểm thấp
    medium: { hex: '#fcf160', rgb: '252, 241, 96', shadow: '0 0 0 2px rgba(252, 241, 96, 0.3)' },  // Vàng - Nguy hiểm trung bình
    high: { hex: '#dd3121', rgb: '221, 49, 33', shadow: '0 0 0 2px rgba(221, 49, 33, 0.3)' },     // Đỏ - Nguy hiểm cao
};

export const useMapCrimeMarkers = ({
    isLeafletLoaded,
    mapInstanceRef,
    markersLayerRef,
    reports,
    onMarkerClick,
    selectedReportId,
}: UseMapCrimeMarkersProps) => {
    useEffect(() => {
        const L = (window as any).L;
        if (!isLeafletLoaded || !mapInstanceRef.current || !markersLayerRef.current || !L) return;

        markersLayerRef.current.clearLayers();

        reports.forEach((report) => {
            if (!report.lat || !report.lng) return;

            const isSelected = report.id === selectedReportId;

            // Màu marker được quyết định bởi mức độ nghiêm trọng (severityLevel)
            const color = severityColorMap[report.severityLevel] ?? severityColorMap.low;

            const isVerified = [VerificationLevel.VERIFIED, VerificationLevel.CONFIRMED].includes(
                report.verificationLevel ?? VerificationLevel.UNVERIFIED
            );
            const isUnverified = report.verificationLevel === VerificationLevel.UNVERIFIED;

            // Tăng size nếu được chọn
            let size = isVerified ? 22 : 16;
            if (isSelected) size = 32; // Size lớn hơn hẳn khi được chọn

            const markerClass = isUnverified ? 'base-marker marker-unverified' : 'base-marker';

            // Style đặc biệt cho marker được chọn
            const selectedStyle = isSelected 
                ? `border: 3px solid #3b82f6; z-index: 1000; transform: scale(1.1); box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.5), ${color.shadow};` 
                : `box-shadow:${color.shadow}, 0 2px 4px rgba(0,0,0,0.2);`;

            const html = `
        <div style="position: relative; width: ${size}px; height: ${size}px;">
          ${isVerified || isSelected ? `<div class="pulse-ring" style="--color-rgb:${isSelected ? '59, 130, 246' : color.rgb}; width: ${size*2}px; height: ${size*2}px; top: -${size/2}px; left: -${size/2}px;"></div>` : ''}
          <div class="${markerClass}" style="background-color:${color.hex} !important;width:100%;height:100%;${selectedStyle}"></div>
        </div>`;

            const marker = L.marker([report.lat, report.lng], {
                icon: L.divIcon({
                    className: isSelected ? 'custom-div-icon selected-marker-icon' : 'custom-div-icon',
                    html,
                    iconSize: [size, size],
                    iconAnchor: [size / 2, size / 2],
                }),
                zIndexOffset: isSelected ? 1000 : 0, // Đưa marker được chọn lên trên cùng
            });

            marker.on('click', (e: any) => {
                L.DomEvent.stopPropagation(e);
                onMarkerClick(report.id);
                mapInstanceRef.current.flyTo([report.lat, report.lng], 16, { duration: 1 });
            });

            markersLayerRef.current.addLayer(marker);
        });
    }, [reports, isLeafletLoaded, mapInstanceRef, markersLayerRef, onMarkerClick, selectedReportId]);
};

'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import { toast } from 'sonner';
import { getDistanceFromLatLonInMeters } from '@/utils/geolocation';
import { VerificationCrimeReport } from '@/types/map';

interface UseMapGeolocationProps {
    isLeafletLoaded: boolean;
    mapInstanceRef: React.MutableRefObject<any>;
    reports: VerificationCrimeReport[];
}

export const useMapGeolocation = ({ isLeafletLoaded, mapInstanceRef, reports }: UseMapGeolocationProps) => {
    const userMarkerRef = useRef<any>(null);
    const watchIdRef = useRef<number | null>(null);

    const [hasLocated, setHasLocated] = useState(false);
    const [alertMessage, setAlertMessage] = useState<string | null>(null);
    const [alertedReportIds, setAlertedReportIds] = useState<Set<string>>(new Set());
    const [currentLocation, setCurrentLocation] = useState<{ lat: number; lng: number } | null>(null);


    const createUserMarker = useCallback((latitude: number, longitude: number, accuracy: number) => {
        const L = (window as any).L;
        const map = mapInstanceRef.current;
        if (!L || !map) return null;

        const accuracyText =
            accuracy > 1000
                ? `<br><span style="color: red; font-size: 11px;">⚠️ Độ chính xác: ±${Math.round(accuracy)}m (Thấp!)</span>`
                : `<br><span style="font-size: 11px;">Độ chính xác: ±${Math.round(accuracy)}m</span>`;

        const icon = L.divIcon({
            className: 'custom-user-marker',
            html: `<div class="my-location-pulse" style="width:16px;height:16px;"></div>`,
            iconSize: [20, 20],
            iconAnchor: [10, 10],
        });

        const marker = L.marker([latitude, longitude], { icon }).addTo(map);
        marker.bindPopup(`<b>Vị trí hiện tại của bạn</b>${accuracyText}`);
        return marker;
    }, [mapInstanceRef]);

    const updateUserMarker = useCallback((latitude: number, longitude: number, accuracy: number) => {
        if (userMarkerRef.current) {
            userMarkerRef.current.setLatLng([latitude, longitude]);
            const accuracyText =
                accuracy > 1000
                    ? `<br><span style="color: red; font-size: 11px;">⚠️ Độ chính xác: ±${Math.round(accuracy)}m (Thấp!)</span>`
                    : `<br><span style="font-size: 11px;">Độ chính xác: ±${Math.round(accuracy)}m</span>`;
            userMarkerRef.current.setPopupContent(`<b>Vị trí hiện tại của bạn</b>${accuracyText}`);
        } else {
            userMarkerRef.current = createUserMarker(latitude, longitude, accuracy);
        }
    }, [createUserMarker]);

    const handleGetLocation = useCallback(() => {
        if (typeof navigator === 'undefined' || !navigator.geolocation) {
            toast.warning('Trình duyệt không hỗ trợ định vị');
            return;
        }

        // Nếu marker đã tồn tại, flyTo đến vị trí hiện tại của marker
        if (userMarkerRef.current) {
            const latlng = userMarkerRef.current.getLatLng();
            const map = mapInstanceRef.current;
            if (map && latlng) {
                map.flyTo([latlng.lat, latlng.lng], 15, { duration: 1.1 });
                return;
            }
        }

        // Nếu chưa có marker, lấy vị trí mới từ GPS
        navigator.geolocation.getCurrentPosition(
            ({ coords }) => {
                const map = mapInstanceRef.current;
                const L = (window as any).L;
                if (!map || !L) return;

                // Cảnh báo nếu độ chính xác quá thấp
                if (coords.accuracy > 1000) {
                    toast.warning(
                        `Độ chính xác GPS thấp (±${Math.round(coords.accuracy)}m). Vị trí có thể không chính xác. Hãy cho phép truy cập vị trí chính xác trong cài đặt trình duyệt.`,
                        { duration: 5000 }
                    );
                }

                // Cập nhật hoặc tạo marker
                if (userMarkerRef.current) {
                    updateUserMarker(coords.latitude, coords.longitude, coords.accuracy);
                } else {
                    userMarkerRef.current = createUserMarker(coords.latitude, coords.longitude, coords.accuracy);
                }

                setCurrentLocation({ lat: coords.latitude, lng: coords.longitude });

                // Luôn flyTo đến vị trí hiện tại
                map.flyTo([coords.latitude, coords.longitude], 15, { duration: 1.1 });
                setHasLocated(true);
            },
            (error) => {
                toast.error('Không thể xác định vị trí của bạn, hãy cho phép ở trình duyệt');
            }
        );
    }, [mapInstanceRef, createUserMarker, updateUserMarker]);

    // Lấy vị trí lần đầu
    useEffect(() => {
        if (isLeafletLoaded && mapInstanceRef.current && !hasLocated) {
            handleGetLocation();
        }
    }, [isLeafletLoaded, hasLocated, handleGetLocation, mapInstanceRef]);

    // Theo dõi vị trí liên tục và kiểm tra cảnh báo nguy hiểm
    useEffect(() => {
        if (
            typeof navigator === 'undefined' ||
            !navigator.geolocation ||
            !isLeafletLoaded ||
            !mapInstanceRef.current
        ) {
            return;
        }

        const L = (window as any).L;
        if (!L) return;

        const handlePositionChange = (pos: GeolocationPosition) => {
            const { latitude, longitude, accuracy } = pos.coords;
            const map = mapInstanceRef.current;
            if (!map) return;



            updateUserMarker(latitude, longitude, accuracy);
            setCurrentLocation({ lat: latitude, lng: longitude });

            if (!hasLocated) {
                setHasLocated(true);
                map.flyTo([latitude, longitude], 15, { duration: 1 });
            }

            reports.forEach((report) => {
                if (!report.lat || !report.lng) return;
                const distance = getDistanceFromLatLonInMeters(latitude, longitude, report.lat, report.lng);
                setAlertedReportIds((prev) => {
                    const next = new Set(prev);
                    if (distance < 500) {
                        // Nếu trong vùng nguy hiểm và chưa cảnh báo
                        if (!prev.has(report.id)) {
                            setAlertMessage(
                                `Bạn đang ở gần khu vực "${report.title}" (~${Math.round(distance)}m). Hãy cẩn thận!`
                            );
                            if (navigator.vibrate) {
                                navigator.vibrate([400, 200, 400]);
                            }
                            next.add(report.id);
                        }
                    } else {
                        // Nếu rời xa khỏi vùng nguy hiểm, xóa để có thể cảnh báo lại khi quay lại
                        next.delete(report.id);
                    }
                    return next;
                });
            });
        };

        watchIdRef.current = navigator.geolocation.watchPosition(
            handlePositionChange,
            (err) => console.warn('Lỗi GPS:', err),
            { enableHighAccuracy: true }
        );

        return () => {
            if (watchIdRef.current !== null) {
                navigator.geolocation.clearWatch(watchIdRef.current);
            }
        };
    }, [isLeafletLoaded, reports, hasLocated, updateUserMarker, mapInstanceRef]);

    return {
        handleGetLocation,
        alertMessage,
        setAlertMessage,
        currentLocation,
    };
};

'use client';

import { useEffect, useRef } from 'react';

export const useMapInit = (isLeafletLoaded: boolean) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<any>(null);
    const markersLayerRef = useRef<any>(null);

    useEffect(() => {
        if (!isLeafletLoaded || !mapContainerRef.current || mapInstanceRef.current) return;

        try {
            const L = (window as any).L;
            if (!L || typeof L.map !== 'function') return;

            const map = L.map(mapContainerRef.current, { zoomControl: false, tap: true }).setView([10.7769, 106.7009], 13);
            L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
                attribution: '&copy; OpenStreetMap &copy; CARTO',
                subdomains: 'abcd',
                maxZoom: 20,
            }).addTo(map);
            L.control.zoom({ position: 'bottomright' }).addTo(map);

            const markersLayer = L.layerGroup().addTo(map);

            mapInstanceRef.current = map;
            markersLayerRef.current = markersLayer;
        } catch (error) {
            console.error('Map Init Error:', error);
        }
    }, [isLeafletLoaded]);

    return {
        mapContainerRef,
        mapInstanceRef,
        markersLayerRef,
    };
};

