type AnimationStyle =
    | "from-bottom"
    | "from-center"
    | "from-top"
    | "from-left"
    | "from-right"
    | "fade"
    | "top-in-bottom-out"
    | "left-in-right-out"

interface HeroVideoProps {
    animationStyle?: AnimationStyle
    videoSrc: string
    thumbnailSrc: string
    thumbnailAlt?: string
    className?: string
}

const animationVariants = {
    "from-bottom": {
        initial: { y: "100%", opacity: 0 },
        animate: { y: 0, opacity: 1 },
        exit: { y: "100%", opacity: 0 },
    },
    "from-center": {
        initial: { scale: 0.5, opacity: 0 },
        animate: { scale: 1, opacity: 1 },
        exit: { scale: 0.5, opacity: 0 },
    },
    "from-top": {
        initial: { y: "-100%", opacity: 0 },
        animate: { y: 0, opacity: 1 },
        exit: { y: "-100%", opacity: 0 },
    },
    "from-left": {
        initial: { x: "-100%", opacity: 0 },
        animate: { x: 0, opacity: 1 },
        exit: { x: "-100%", opacity: 0 },
    },
    "from-right": {
        initial: { x: "100%", opacity: 0 },
        animate: { x: 0, opacity: 1 },
        exit: { x: "100%", opacity: 0 },
    },
    fade: {
        initial: { opacity: 0 },
        animate: { opacity: 1 },
        exit: { opacity: 0 },
    },
    "top-in-bottom-out": {
        initial: { y: "-100%", opacity: 0 },
        animate: { y: 0, opacity: 1 },
        exit: { y: "100%", opacity: 0 },
    },
    "left-in-right-out": {
        initial: { x: "-100%", opacity: 0 },
        animate: { x: 0, opacity: 1 },
        exit: { x: "100%", opacity: 0 },
    },
}

export function HeroVideoDialog({
    animationStyle = "from-center",
    videoSrc,
    thumbnailSrc,
    thumbnailAlt = "Video thumbnail",
    className,
}: HeroVideoProps) {
    const [isVideoOpen, setIsVideoOpen] = useState(false)
    const selectedAnimation = animationVariants[animationStyle]

    return (
        <div className={cn("relative", className)}>
            <button
                type="button"
                aria-label="Play video"
                className="group relative cursor-pointer border-0 bg-transparent p-0"
                onClick={() => setIsVideoOpen(true)}
            >
                <Image
                    src={thumbnailSrc}
                    alt={thumbnailAlt}
                    width={1920}
                    height={1080}
                    className="w-full rounded-md border shadow-lg transition-[filter] duration-200 ease-out group-hover:brightness-[0.8]"
                />
                <div className="absolute inset-0 flex scale-[0.9] items-center justify-center rounded-2xl transition-transform duration-200 ease-out group-hover:scale-100">
                    <div className="bg-primary/10 flex size-28 items-center justify-center rounded-full backdrop-blur-md">
                        <div
                            className={`from-primary/30 to-primary relative flex size-20 scale-100 items-center justify-center rounded-full bg-gradient-to-b shadow-md transition-transform duration-200 ease-out group-hover:scale-[1.2]`}
                        >
                            <Play
                                className="size-8 scale-100 fill-white text-white transition-transform duration-200 ease-out group-hover:scale-105"
                                style={{
                                    filter:
                                        "drop-shadow(0 4px 3px rgb(0 0 0 / 0.07)) drop-shadow(0 2px 2px rgb(0 0 0 / 0.06))",
                                }}
                            />
                        </div>
                    </div>
                </div>
            </button>
            <AnimatePresence>
                {isVideoOpen && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        role="button"
                        tabIndex={0}
                        onKeyDown={(e) => {
                            if (e.key === "Escape" || e.key === "Enter" || e.key === " ") {
                                setIsVideoOpen(false)
                            }
                        }}
                        onClick={() => setIsVideoOpen(false)}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-md"
                    >
                        <motion.div
                            {...selectedAnimation}
                            transition={{ type: "spring", damping: 30, stiffness: 300 }}
