import type { NextAuthConfig } from "next-auth"
import Credentials from "next-auth/providers/credentials"
import { env } from "../lib/env"
import { isPublicRoute, isAuthRoute, DEFAULT_LOGIN_REDIRECT } from "./routes"
import type { JWT } from "next-auth/jwt"

/**
 * Takes a token, and returns a new token with updated
 * `accessToken` and `accessTokenExpires`. If an error occurs,
 * returns the old token and an error property is added
 */
async function refreshAccessToken(token: JWT) {
    try {
        const apiUrl = env.NEXT_PUBLIC_API_BASE_URL.endsWith('/api')
            ? `${env.NEXT_PUBLIC_API_BASE_URL}/auth/refresh`
            : `${env.NEXT_PUBLIC_API_BASE_URL}/api/auth/refresh`;

        const response = await fetch(apiUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                refreshToken: token.refreshToken,
            }),
        })

        const refreshedTokens = await response.json()

        if (!response.ok) {
            throw refreshedTokens
        }

        console.log('[JWT Callback] Token refresh successful')

        return {
            ...token,
            accessToken: refreshedTokens.accessToken,
            refreshToken: refreshedTokens.refreshToken ?? token.refreshToken, // Fall back to old refresh token
            accessTokenExpires: Date.now() + (3600 - 300) * 1000, // 55 minutes
        }
    } catch (error) {
        console.error('[JWT Callback] Token refresh failed:', error)

        return {
            ...token,
            error: "RefreshAccessTokenError",
        }
    }
}


export const authConfig = {
    pages: {
        signIn: '/login',
    },
    callbacks: {
        authorized({ auth, request: { nextUrl } }) {
            const isLoggedIn = !!auth?.user
            const pathname = nextUrl.pathname

            // Public routes - always allowed ok
            if (isPublicRoute(pathname)) {
                return true
            }

            // Auth routes - redirect logged in users away
            if (isAuthRoute(pathname)) {
                if (isLoggedIn) {
                    return Response.redirect(new URL(DEFAULT_LOGIN_REDIRECT, nextUrl))
                }
                return true
            }

            // Protected routes - require authentication
            if (isLoggedIn) {
                return true
            }

            return false // Redirect unauthenticated users to login page
        },
        async jwt({ token, user, account }) {
            // Initial sign in
            if (account && user) {
                return {
                    accessToken: user.accessToken,
                    refreshToken: user.refreshToken,
                    userId: user.userId,
                    role: user.role,
                    // Set token expiry time (JWT_EXPIRES_IN=1h = 3600 seconds)
                    // Subtract 5 minutes buffer to refresh before actual expiry
                    accessTokenExpires: Date.now() + (3600 - 300) * 1000, // 55 minutes
                }
            }

            // Return previous token if the access token has not expired yet
            const tokenExpires = token.accessTokenExpires as number || 0;
            if (Date.now() < tokenExpires) {
                return token
            }

            // Access token has expired, try to refresh it
            console.log('[JWT Callback] Access token expired, refreshing...')
            return refreshAccessToken(token)
        },
        async session({ session, token }) {
            // Force sign out if token refresh failed
            if (token.error) {
                console.error('[Session Callback] Token refresh error detected, invalidating session')
                return null as any  // This will force logout
            }

            if (token) {
                session.user = {
                    ...session.user,
                    id: token.userId as string,
                    role: token.role as string | null,
                }
                session.accessToken = token.accessToken as string
                session.refreshToken = token.refreshToken as string
            }
            return session
        },
    },
    providers: [
        Credentials({
            name: "Credentials",
            credentials: {
                email: { label: "Email", type: "email" },
                password: { label: "Password", type: "password" }
            },
            async authorize(credentials) {
                if (!credentials?.email || !credentials?.password) {
                    console.error('[Auth] Missing credentials')
                    return null
                }

                try {
                    const apiUrl = env.NEXT_PUBLIC_API_BASE_URL.endsWith('/api')
                        ? `${env.NEXT_PUBLIC_API_BASE_URL}/auth/login`
                        : `${env.NEXT_PUBLIC_API_BASE_URL}/api/auth/login`

                    const response = await fetch(apiUrl, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        body: JSON.stringify({
                            email: credentials.email,
                            password: credentials.password,
                        }),
                    })


                    if (!response.ok) {
                        const errorText = await response.text()
                        console.error('[Auth] API Error:', {
                            status: response.status,
                            statusText: response.statusText,
                            body: errorText
                        })
                        return null
                    }

                    const data = await response.json()

                    if (data.accessToken) {
                        return {
                            id: data.user?.id || data.userId || '',
                            email: credentials.email as string,
                            name: data.user?.name || '',
                            role: data.user?.role || data.role || null, // Lấy role từ BE
                            accessToken: data.accessToken,
                            refreshToken: data.refreshToken,
                            userId: data.user?.id || data.userId || '',
                        }
                    }

                    console.error('[Auth] No accessToken in response')
                    return null
                } catch (error) {
                    console.error('[Auth] Fetch error:', error)
                    if (error instanceof Error) {
                        console.error('[Auth] Error message:', error.message)
                        console.error('[Auth] Error cause:', error.cause)

                        // Check if it's a network error (backend not running)
                        const errorMessage = error.message.toLowerCase()
                        const errorCause = error.cause as any

                        if (errorMessage.includes('fetch failed') ||
                            errorMessage.includes('failed to fetch') ||
                            errorMessage.includes('networkerror') ||
                            errorCause?.code === 'ECONNREFUSED' ||
                            errorCause?.code === 'ENOTFOUND') {
                            // Log connection error but return null
                            // The login form will detect this and show appropriate message
                            console.error('[Auth] Connection error detected - server may not be running')
                            return null
                        }
                    }
                    // Return null for other errors - NextAuth will handle it
                    return null
                }
            },
        }),
    ],
} satisfies NextAuthConfig

/**
 * An array of routes that are accessible to the public
 * These routes do not require authentication
 */
export const publicRoutes = [
    "/", // Landing page - public
    "/dashboard", // Dashboard - public, không cần đăng nhập
    "/weather",
    "/wanted",
    "/terms",
    "/privacy",
    "/about",
] as const;

/**
 * An array of routes that are used for authentication
 * These routes will redirect logged in users to `DEFAULT_LOGIN_REDIRECT`
 */
export const authRoutes = [
    "/login",
    "/signup",
    "/reset-password",
    "/forgot-password",
] as const;

/**
 * An array of routes that require admin role
 * Only users with role "admin" can access these routes
 */
export const adminRoutes = [
    "/admin",
    "/admin/users",
    "/admin/settings",
    "/admin/reports",
] as const;

/**
 * An array of routes that require officer role
 * Users with role "admin" or "officer" can access these routes
 */
export const officerRoutes = [
    "/reports/create",
    "/reports/manage",
] as const;

/**
 * The default redirect path after a user logs in
 */
export const DEFAULT_LOGIN_REDIRECT = "/dashboard";

/**
 * The default redirect path after a user logs out
 */
export const DEFAULT_LOGOUT_REDIRECT = "/";

/**
 * The redirect path for unauthorized access
 */
export const UNAUTHORIZED_REDIRECT = "/unauthorized";

/**
 * Helper function to check if a path is a public route
 */
export function isPublicRoute(pathname: string): boolean {
    // Check exact match first
    if (publicRoutes.includes(pathname as any)) {
        return true
    }
    // Check if pathname starts with any public route (but not just "/")
    return publicRoutes.some(route => {
        if (route === "/") {
            return false // "/" should only match exactly
        }
        return pathname.startsWith(route)
    })
}

/**
 * Helper function to check if a path is an auth route
 */
export function isAuthRoute(pathname: string): boolean {
    return authRoutes.some(route => pathname.startsWith(route))
}

/**
 * Helper function to check if a path is an admin route
 */
export function isAdminRoute(pathname: string): boolean {
    return adminRoutes.some(route => pathname.startsWith(route))
}

/**
 * Helper function to check if a path is an officer route
 */
export function isOfficerRoute(pathname: string): boolean {
    return officerRoutes.some(route => pathname.startsWith(route))
}

/**
 * Helper function to check if a path is an API auth route
 */
export function isApiAuthRoute(pathname: string): boolean {
    return pathname.startsWith("/api/auth")
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import reportService, { CrimeReportResponse, CrimeType, CreateCrimeReportDto, UpdateCrimeReportDto } from '@/service/report.service';
import { VerificationCrimeReport, VerificationLevel } from '@/types/map';
import { statisticsKeys } from './use-statistics';

// Query keys for cache management
export const reportsKeys = {
    all: ['reports'] as const,
    lists: () => [...reportsKeys.all, 'list'] as const,
    list: (type?: CrimeType) => [...reportsKeys.lists(), { type }] as const,
    mine: () => [...reportsKeys.all, 'mine'] as const,
    detail: (id: string) => [...reportsKeys.all, 'detail', id] as const,
};

export const normalizeReport = (report: CrimeReportResponse): VerificationCrimeReport => ({
    ...report,
    severityLevel: report.severityLevel ?? 'low',
    trustScore: report.trustScore ?? 0,
    verificationLevel: (report.verificationLevel as VerificationLevel) ?? VerificationLevel.UNVERIFIED,
    confirmationCount: report.confirmationCount ?? 0,
    disputeCount: report.disputeCount ?? 0,
});

// ============================================
// React Query versions (with caching)
// ============================================

/**
 * React Query hook for fetching all crime reports with caching
 * Data is shared between dashboard and reports pages
 */
export function useReportsQuery(type?: CrimeType) {
    return useQuery({
        queryKey: reportsKeys.list(type),
        queryFn: async () => {
            const data = await reportService.findAll(type);
            return data.map(normalizeReport);
        },
    });
}

/**
 * React Query hook for fetching current user's reports with caching
 */
export function useMyReportsQuery() {
    return useQuery({
        queryKey: reportsKeys.mine(),
        queryFn: async () => {
            const data = await reportService.findMine();
            return data.map(normalizeReport);
        },
    });
}

/**
 * Mutation hook for creating a report
 */
export function useCreateReport() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: (payload: CreateCrimeReportDto) => reportService.create(payload),
        onSuccess: (data) => {
            const normalized = normalizeReport(data);
            // Update all report lists
            queryClient.invalidateQueries({ queryKey: reportsKeys.lists() });
            // Update my reports
            queryClient.invalidateQueries({ queryKey: reportsKeys.mine() });
            // Invalidate statistics to update total count
            queryClient.invalidateQueries({ queryKey: statisticsKeys.statistics() });
        },
    });
}

/**
 * Mutation hook for confirming a report
 */
export function useConfirmReport() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: (id: string) => reportService.confirmReport(id),
        onSuccess: (data) => {
            const normalized = normalizeReport(data);
            // Update all report lists in cache
            queryClient.setQueriesData<VerificationCrimeReport[]>(
                { queryKey: reportsKeys.lists() },
                (old) => old?.map((r) => (r.id === normalized.id ? normalized : r))
            );
        },
    });
}

